## II. THE STATE MACHINE: "Quantum States"

Not simple enums. Each state is a ** behavioral class** with entry/exit lifecycle hooks:

```javascript
// core/FiniteStateMachine.js
const STATES = {
  DISCONNECTED: {
    entry: (ctx) => ctx.ui.showReconnecting(),
    exit: (ctx) => ctx.ui.hideOverlay(),
    allowed: ['CONNECTED']
  },
  CONNECTED: {
    entry: (ctx) => ctx.rust.handshake(),
    allowed: ['PROJECT_LINKED', 'DISCONNECTED']
  },
  PROJECT_LINKED: {
    entry: (ctx) => ctx.timeline.captureBaseline(),
    exit: (ctx) => ctx.timeline.releaseBaseline(),
    allowed: ['ANALYZING', 'CONNECTED']
  },
  ANALYZING: {
    entry: (ctx) => {
      ctx.rust.sendAnalyzeJob();
      ctx.ui.showProgressiveBars();
    },
    // Streaming results handling
    onDataChunk: (ctx, chunk) => ctx.buffer.ingest(chunk),
    allowed: ['RESULTS_READY', 'ERROR']
  },
  RESULTS_READY: {
    entry: (ctx) => {
      ctx.timeline.renderGhostPreview(); // Non-destructive
      ctx.dashboard.sync('analysis_complete');
    },
    allowed: ['APPLIED', 'PROJECT_LINKED', 'ANALYZING']
  },
  APPLIED: {
    entry: (ctx) => ctx.timeline.commitTransaction(),
    exit: (ctx) => ctx.timeline.snapshotForUndo(),
    allowed: ['PROJECT_LINKED'] // Reset only
  }
};

class LensStateMachine {
  transition(event, payload) {
    const next = STATES[this.current].allowed.find(s => s === event.target);
    if (!next) throw new StateViolationError(`${this.current} → ${event.target}`);

    STATES[this.current].exit?.(this.context);
    this.current = next;
    STATES[next].entry?.(this.context);

    // Broadcast to Web Dashboard
    this.context.dashboard.broadcast('state_change', {
      state: next,
      timestamp: performance.now(),
      project: this.context.project.id
    });
  }
}
```

